        for i, c in enumerate(s):
            if c.isdigit():
                num = int(c)
                if i > 0 and s[i-1] in "+-":
                    res += sign * num
            elif c in "+-":
                if i > 0 and s[i-1] == "(":
                    sign = 1 if c == "+" else -1
