from itertools import permutations

class Solution(object):
    def nextPermutation(self, nums):
        """
        :type nums: List[int]
        :rtype: None Do not return anything, modify nums in-place instead.
        """
        # Find the position where the sequence breaks (from right to left)
        for i in range(len(nums)-1, -1, -1):
            if nums[i] < nums[i-1]:
                break

        # If the sequence is already in descending order, no need to find the next permutation
        if i == 0:
            return nums.reverse()

        # Find the first number from right that is smaller than its predecessor
        for j in range(i-1, -1, -1):
            if nums[j] < nums[i-1]:
                break

        # Swap the two numbers and reverse the right part
        nums[i-1], nums[j] = nums[j], nums[i-1]
        nums[i:] = list(permutations(nums[i:], len(nums[i:])))[0]

