        """
        :type s1: str
        :type s2: str
        :type s3: str
        :rtype: bool
        """
        len1, len2, len3 = len(s1), len(s2), len(s3)
        dp = [[False]*(len3+1) for _ in range(len2+1)]

        # Initialize dp[0][0] as True
