        # Initialize dp[0][j] as True if j is multiple of 2
        for j in range(1, len3+1, 2):
            if j-1 < len1 and s1[j-1] == s3[j-1]:
                dp[0][j] = True
        # Initialize dp[i][0] as True if i is multiple of 2
        for i in range(1, len2+1, 2):
            if i-1 < len1 and s2[i-1] == s3[i-1]:
                dp[i][0] = True

        # Fill the dp table
        for i in range(1, len2+1):
            for j in range(1, len3+1):
                if s2[i-1] == s3[j-1]:
                    dp[i][j] = dp[i-1][j-1]
                else:
