from collections import deque

class Solution(object):
    def levelOrderBottom(self, root):
        if not root:
            return []

        # Using deque for the queue, and list for the result
        res = [[]]
        q = deque([(root, 0)])

        while q:
            node, level = q.popleft()

            # If the current level is not in the result, append it
            if len(res) == level + 1:
                res.append([])

            # Append the value of the current node to the current level
            res[level + 1].append(node.val)

            # Add the children of the current node to the queue
            if node.left:
                q.append((node.left, level + 1))
            if node.right:
                q.append((node.right, level + 1))

        # Reverse the result to get the bottom-up level order traversal
        return res[::-1]

