    def uniquePaths(self, m, n):
        """
        :type m: int
        :type n: int
        :rtype: int
        """
        # Create a grid with m+1 rows and n+1 columns. Initialize the last row and last column as 1.
        grid = [[0]*(n+1) for _ in range(m+1)]
        for i in range(m+1):
            grid[i][-1] = 1
        for j in range(n+1):
            grid[-1][j] = 1

        # Loop through the grid from the second last row and last column to the top-left corner.
        # For each cell, the number of unique paths to reach it is the sum of the number of paths from the cell above and the cell to the left.
        for i in range(m-1, -1, -1):
            for j in range(n-1, -1, -1):
                grid[i][j] = grid[i+1][j] + grid[i][j+1]

