    def divide(self, dividend, divisor):
        """
        :type dividend: int
        :type divisor: int
        :rtype: int
        """
        if dividend == 0:
            return 0

        sign = 1

        if (dividend < 0) ^ (divisor < 0):
            sign = -1

        dividend, divisor = abs(dividend), abs(divisor)

        quotient = 0

        while dividend >= divisor:
            temp = divisor
            count = 0

            while dividend >= temp:
                dividend -= temp
                temp <<= 1
                count += 1

            quotient += count

        if sign == -1:
            quotient = -quotient

        if quotient > 2**31 - 1:
            quotient = 2**31 - 1
        elif quotient < -2**31:
            quotient = -2**31

        return quotient

