from collections import deque

def slidingPuzzle(board):
    def isValid(board):
        for i in range(2):
            for j in range(3):
                if board[i][j]!= 0 and (i, j)!= self.target[board[i][j]]:
                    return False
        return True

    def neighbors(board, i, j):
        dirs = [(i + 1, j), (i - 1, j), (i, j + 1), (i, j - 1)]
        return [(x, y) for x, y in dirs if 0 <= x < 2 and 0 <= y < 3 and board[x][y]!= 0]

    self.board, self.target = board, [(1, 1, 2), (4, 0, 3), (5, 6, 7)]

    queue = deque([(board, 0)])
    visited = {tuple(board)}

    while queue:
        board, moves = queue.popleft()
        if isValid(board):
            return moves

        for i, j in self.target:
            if board[i][j] == 0:
                continue
            for x, y in neighbors(board, i, j):
                swap = board[i][j], board[x][y]
                board[i][j], board[x][y] = swap, 0
                if tuple(board) not in visited:
                    queue.append((list(board), moves + 1))
                    visited.add(tuple(board))
                board[i][j], board[x][y] = swap, 0  # backtrack

    return -1

