    def convert(self, s, numRows):
        if numRows == 1:
            return s
        s = list(s)
        n = len(s)
        zigzag = [""] * numRows
        index = 0
        for i in range(n):
            if i % 2 == 0:
                zigzag[index] += s[i]
            else:
                zigzag[numRows-1-index] += s[i]
            index = (index + 1) % numRows
        return "".join(zigzag)

