class Solution(object):
    def countOfAtoms(self, formula):
        count = Counter()
        i = 0
        while i < len(formula):
            if formula[i].isupper():
                j = i + 1
                while j < len(formula) and formula[j].islower():
                    j += 1
                count[formula[i:j]] += 1
