from bisect import bisect_right

def minPatches(nums, n):
    def check(m):
        i = 0
        j = 0
        while j < len(nums):
            if nums[j] > m:
                break
            i += bisect_right(nums, m - nums[j], j)
            j += 1
        return i

    l, r = 1, n
    while l <= r:
        mid = (l + r) // 2
        if check(mid) < mid:
            l = mid + 1
        else:
            r = mid - 1

    return l - 1

