import heapq

class Solution(object):
    def findKthNumber(self, m, n, k):
        """
        :type m: int
        :type n: int
        :type k: int
        :rtype: int
        """
        pq = []
        for i in range(1, m+1):
            for j in range(1, n+1):
                if len(pq) < k:
                    heapq.heappush(pq, (i*j, i, j))
                else:
                    if i*j < pq[0][0]:
                        heapq.heappop(pq)
                        heapq.heappush(pq, (i*j, i, j))
        return pq[0][0]

