class Solution(object):
    def recoverTree(self, root):
        def swap(x, y):
            x.val, y.val = y.val, x.val

        def Morris(root):
            prev = None
            while root:
                if root.left is None:
                    if prev is not None:
                        swap(prev, root)
                    prev = root
                    root = root.right
                else:
                    temp = root.left
                    while temp.right and temp.right!= root:
                        temp = temp.right

                    if temp.right is None:
                        if prev is not None:
                            swap(prev, root)
                        temp.right = root
                        root = root.right
                        prev = root
                    else:
                        temp.right = None
                        if prev is not None:
                            swap(prev, root)
                        root = root.right
                        prev = root

        Morris(root)

