class Solution(object):
    def isPerfectSquare(self, num):
        """
        :type num: int
        :rtype: bool
        """
        # If num is 0 or 1, it is a perfect square
        if num <= 1:
            return True

        # Binary search for the square root
        left, right = 1, num // 2
        while left <= right:
            mid = (left + right) // 2
            square = mid * mid
            if square < num:
                left = mid + 1
            elif square > num:
                right = mid - 1
            else:
                # Found the perfect square, but it is not the square root.
                # Adjust it to the square root.
                if mid == 1:
                    return True
                else:
                    right = mid - 1
        return False

