    def findComplement(self, num):
        # Initialize result
        res = 0

        # While num is greater than 0
        while num > 0:
            # If the least significant bit of num is 0, add 1 to the result and remove the least significant bit
            # If the least significant bit of num is 1, add 0 to the result and remove the least significant bit
            if num & 1:
